import React, { useState, useRef, useEffect } from "react";
import axios from "axios";
import { motion, AnimatePresence } from "framer-motion";
import "./styles.css";

// ─────────────────────────────────────────────────────────────
// FIX: أضفنا كل حقول الـ CV للـ interface
// ─────────────────────────────────────────────────────────────
interface Candidate {
  id: string;
  name: string;
  match_score: number;
  rerank_score: number;
  skill_score: number;
  final_score: number;
  technical_skills?: string;
  tools?: string;
  soft_skills?: string;
  summary?: string;
  experience?: string;
  education?: string;
  projects?: string;
  certifications?: string;
  languages?: string;
  accomplishments?: string;
}

interface Analysis {
  category: string;
  experience_level: string;
  technical_skills: string[];
  summary: string;
}

const API_BASE_URL = "http://localhost:8000";

export default function App() {
  const [jdText, setJdText]         = useState<string>("");
  const [loading, setLoading]       = useState<boolean>(false);
  const [results, setResults]       = useState<Candidate[]>([]);
  const [analysis, setAnalysis]     = useState<Analysis | null>(null);
  const [error, setError]           = useState<string>("");
  const [selected, setSelected]     = useState<Candidate | null>(null);

  const [chatInput, setChatInput]       = useState("");
  const [chatMessages, setChatMessages] = useState<{ role: string; text: string }[]>([]);
  const [chatHistory, setChatHistory]   = useState<any[]>([]);
  const [chatLoading, setChatLoading]   = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chatMessages]);

  useEffect(() => {
    setChatMessages([]);
    setChatHistory([]);
    setChatInput("");
  }, [selected]);

  const startMatching = async () => {
    if (!jdText.trim()) return;
    setError("");
    setLoading(true);
    setResults([]);
    setAnalysis(null);
    setSelected(null);
    setChatMessages([]);
    setChatHistory([]);

    try {
      const response = await axios.post(`${API_BASE_URL}/search`, {
        job_description: jdText,
        top_k: 10,
      });
      setResults(response.data.candidates);
      setAnalysis(response.data.analysis);
    } catch (err) {
      setError("Connection failed! Make sure the backend is running.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleChat = async () => {
    if (!chatInput.trim()) return;
    const userMsg = chatInput;
    setChatInput("");
    setChatMessages((prev) => [...prev, { role: "user", text: userMsg }]);
    setChatLoading(true);

    try {
      const response = await axios.post(`${API_BASE_URL}/chat`, {
        question: userMsg,
        history: chatHistory,
        // ─────────────────────────────────────────────────────
        // FIX: دايماً ابعث كل المرشحين — مش بس المختار
        //      عشان الـ AI يقدر يقارن بينهم
        // ─────────────────────────────────────────────────────
        candidate_ids: results.map((c) => c.id),
      });
      setChatHistory(response.data.history);
      setChatMessages((prev) => [...prev, { role: "ai", text: response.data.answer }]);
    } catch {
      setChatMessages((prev) => [...prev, { role: "ai", text: "Connection error." }]);
    } finally {
      setChatLoading(false);
    }
  };

  const scoreColor = (score: number) => {
    if (score >= 0.7) return "#22c55e";
    if (score >= 0.4) return "#fbbf24";
    return "#ef4444";
  };

  return (
    <div className="app">

      {/* ── NAV ── */}
      <header className="nav">
        <div className="nav-left">
          <div className="logo-box">
            <span className="logo-itg">ITG</span>
          </div>
          <div className="logo-name">
            <span className="logo-smart">Smart</span>
            <span className="logo-matcher">Matcher</span>
          </div>
          <div className="nav-divider" />
          <span className="nav-sub">AI Talent Intelligence</span>
        </div>
        <div className="nav-right">
          {analysis && (
            <>
              <span className="pill-cat">{analysis.category}</span>
              <span className="pill-lvl">{analysis.experience_level}</span>
            </>
          )}
        </div>
      </header>

      <div className="workspace">

        {/* ── LEFT: JD INPUT ── */}
        <aside className="left-panel">
          <p className="panel-label">Job Description</p>
          <textarea
            className="jd-input"
            value={jdText}
            onChange={(e) => setJdText(e.target.value)}
            placeholder="Paste the full job description here..."
          />
          {error && <p className="err">{error}</p>}
          <button
            className={`match-btn ${loading ? "busy" : ""}`}
            onClick={startMatching}
            disabled={loading}
          >
            {loading ? (
              <span className="dots">
                Analyzing<span>.</span><span>.</span><span>.</span>
              </span>
            ) : "Find Best Candidates"}
          </button>

          {analysis?.technical_skills && analysis.technical_skills.length > 0 && (
            <div className="skills-section">
              <p className="skills-label">Extracted Skills</p>
              <div className="skills-wrap">
                {analysis.technical_skills.slice(0, 8).map((s, i) => (
                  <span key={i} className="skill-tag">{s}</span>
                ))}
              </div>
            </div>
          )}

          {analysis?.summary && (
            <div className="summary-box">
              <p className="summary-label">Role Summary</p>
              <p className="summary-text">{analysis.summary}</p>
            </div>
          )}
        </aside>

        {/* ── CENTER: CANDIDATES LIST ── */}
        <main className="center-panel">
          <div className="list-header">
            <h2 className="list-title">Matched Talent Pool</h2>
            {results.length > 0 && (
              <span className="list-count">{results.length} candidates</span>
            )}
          </div>

          <div className="candidates-list">
            <AnimatePresence>
              {results.map((cand, idx) => (
                <motion.div
                  key={cand.id}
                  initial={{ opacity: 0, x: -16 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: idx * 0.06 }}
                  className={`cand-card ${selected?.id === cand.id ? "active" : ""}`}
                  onClick={() => setSelected(cand)}
                >
                  <div className="cand-rank">#{idx + 1}</div>
                  <div className="cand-info">
                    <h4 className="cand-name">{cand.name || "Anonymous"}</h4>
                    <span className="cand-id">REF: {cand.id}</span>
                    <div className="cand-skills">
                      {cand.technical_skills?.split(",").slice(0, 3).map((s, i) => (
                        <span key={i} className="cand-skill-tag">{s.trim()}</span>
                      ))}
                    </div>
                  </div>
                  <div className="cand-score">
                    <svg viewBox="0 0 36 36" className="score-svg">
                      <path className="score-bg-path" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" />
                      <path
                        className="score-fill-path"
                        stroke={scoreColor(cand.final_score)}
                        strokeDasharray={`${Math.round(cand.final_score * 100)}, 100`}
                        d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
                      />
                    </svg>
                    <span className="score-pct" style={{ color: scoreColor(cand.final_score) }}>
                      {Math.round(cand.final_score * 100)}%
                    </span>
                  </div>
                </motion.div>
              ))}
            </AnimatePresence>

            {!loading && results.length === 0 && (
              <div className="empty-state">
                <div className="empty-icon">⬡</div>
                <p>Paste a job description and click<br /><strong>Find Best Candidates</strong></p>
              </div>
            )}
          </div>
        </main>

        {/* ── RIGHT: DRAWER ── */}
        <AnimatePresence>
          {selected && (
            <motion.aside
              className="drawer"
              initial={{ x: 340, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              exit={{ x: 340, opacity: 0 }}
              transition={{ type: "spring", stiffness: 300, damping: 30 }}
            >
              <button className="drawer-close" onClick={() => setSelected(null)}>✕</button>

              {/* Header */}
              <div className="drawer-header">
                <div className="drawer-avatar">
                  {(selected.name || "??").split(" ").map(n => n[0]).slice(0, 2).join("").toUpperCase()}
                </div>
                <div>
                  <h3 className="drawer-name">{selected.name || "Anonymous"}</h3>
                  <span className="drawer-id">REF: {selected.id}</span>
                </div>
              </div>

              {/* Score bars */}
              <div className="drawer-scores">
                {[
                  { label: "Semantic Match", val: selected.match_score,  color: "#1d4ed8" },
                  { label: "Rerank Score",   val: selected.rerank_score, color: "#60a5fa" },
                  { label: "Skill Match",    val: selected.skill_score,  color: "#fbbf24" },
                ].map(s => (
                  <div key={s.label} className="dscore-row">
                    <span className="dscore-label">{s.label}</span>
                    <div className="dscore-bar-bg">
                      <div className="dscore-bar-fill" style={{ width: `${s.val * 100}%`, background: s.color }} />
                    </div>
                    <span className="dscore-pct">{Math.round(s.val * 100)}%</span>
                  </div>
                ))}
                <div className="dscore-total">
                  <span>Final Score</span>
                  <span style={{ color: scoreColor(selected.final_score), fontWeight: 600 }}>
                    {Math.round(selected.final_score * 100)}%
                  </span>
                </div>
              </div>

              {/* Summary */}
              {selected.summary && (
                <div className="drawer-section">
                  <p className="drawer-section-label">Summary</p>
                  <p className="drawer-detail-text">{selected.summary}</p>
                </div>
              )}

              {/* Technical Skills */}
              {selected.technical_skills && (
                <div className="drawer-section">
                  <p className="drawer-section-label">Technical Skills</p>
                  <div className="drawer-skills-wrap">
                    {selected.technical_skills.split(",").map((s, i) => (
                      <span key={i} className="drawer-skill-tag">{s.trim()}</span>
                    ))}
                  </div>
                </div>
              )}

              {/* Tools */}
              {selected.tools && (
                <div className="drawer-section">
                  <p className="drawer-section-label">Tools</p>
                  <div className="drawer-skills-wrap">
                    {selected.tools.split(",").map((s, i) => (
                      <span key={i} className="drawer-skill-tag drawer-skill-tool">{s.trim()}</span>
                    ))}
                  </div>
                </div>
              )}

              {/* Experience */}
              {selected.experience && (
                <div className="drawer-section">
                  <p className="drawer-section-label">Experience</p>
                  <p className="drawer-detail-text">{selected.experience}</p>
                </div>
              )}

              {/* Education */}
              {selected.education && (
                <div className="drawer-section">
                  <p className="drawer-section-label">Education</p>
                  <p className="drawer-detail-text">{selected.education}</p>
                </div>
              )}

              {/* Projects */}
              {selected.projects && (
                <div className="drawer-section">
                  <p className="drawer-section-label">Projects</p>
                  <p className="drawer-detail-text">{selected.projects}</p>
                </div>
              )}

              {/* Certifications */}
              {selected.certifications && (
                <div className="drawer-section">
                  <p className="drawer-section-label">Certifications</p>
                  <p className="drawer-detail-text">{selected.certifications}</p>
                </div>
              )}

              {/* Chat */}
              <div className="drawer-chat">
                <p className="drawer-section-label">
                  AI Assistant
                  <span className="chat-scope-hint"> — all {results.length} candidates</span>
                </p>
                <div className="drawer-chat-window">
                  {chatMessages.length === 0 && (
                    <p className="drawer-chat-hint">
                      Ask anything — e.g. "Who is best at React?" or "Compare top 3"
                    </p>
                  )}
                  {chatMessages.map((msg, i) => (
                    <div key={i} className={`drawer-bubble ${msg.role}`}>{msg.text}</div>
                  ))}
                  {chatLoading && (
                    <div className="drawer-bubble ai thinking">Analyzing all candidates...</div>
                  )}
                  <div ref={chatEndRef} />
                </div>
                <div className="drawer-chat-input">
                  <input
                    type="text"
                    value={chatInput}
                    onChange={(e) => setChatInput(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && handleChat()}
                    placeholder="Who is best at SQL? Compare top 3..."
                  />
                  <button onClick={handleChat} disabled={chatLoading}>→</button>
                </div>
              </div>

            </motion.aside>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
